-- Run after 003a_pulse_columns.sql. Part 4 of 4.
insert into public.missions (
  mission_id_slug,
  title,
  mission,
  world,
  category,
  difficulty,
  xp,
  time_required,
  mission_path,
  tags,
  pack,
  unlock_xp,
  why_it_matters,
  completion_condition,
  reflection_prompt,
  safety_note,
  is_sensitive,
  is_active
)
values
  ('i_want_to_reset_my_life_i_only_have_5_minutes_1_do_a_five_minute_trash_sweep', 'Do a Five-Minute Trash Sweep', 'Set a five-minute timer and remove obvious trash, old cups, wrappers, receipts, or dead clutter from one area.', 'Reset', 'Clear Space', 'Easy', 10, 'I only have 5 minutes', 'I want to reset my life', array['quick', 'easy', 'reset', 'admin', 'focus', 'money']::text[], 'Starter', 0, 'Visible mess often starts with tiny things nobody decided to remove.', 'One area has less visible trash than before.', 'What felt instantly better after the sweep?', null, false, true),
  ('i_want_to_reset_my_life_i_only_have_5_minutes_2_capture_the_loose_ends', 'Capture the Loose Ends', 'Write every loose task in your head into one list without organizing it yet.', 'Reset', 'Clear Space', 'Easy', 10, 'I only have 5 minutes', 'I want to reset my life', array['quick', 'easy', 'reset', 'admin', 'focus', 'money']::text[], 'Starter', 0, 'A captured list is easier to face than a cloud of invisible pressure.', 'Your loose ends are captured in one place.', 'Which loose end had been floating around longest?', null, false, true),
  ('i_want_to_reset_my_life_i_only_have_5_minutes_3_set_tomorrow_s_first_item', 'Set Tomorrow''s First Item', 'Place one item where tomorrow-you will need it: clothes, bag, keys, bottle, notebook, charger, or shoes.', 'Reset', 'Clear Space', 'Easy', 10, 'I only have 5 minutes', 'I want to reset my life', array['quick', 'easy', 'reset', 'admin', 'focus', 'money']::text[], 'Starter', 0, 'Future friction drops when the first step is already visible.', 'One useful item is ready where you will need it.', 'What did you make easier for tomorrow?', null, false, true),
  ('i_want_to_reset_my_life_i_have_10_15_minutes_1_reset_one_friction_spot', 'Reset One Friction Spot', 'Choose one tiny area you touch daily and remove, return, or wipe everything until tomorrow-you can use it without thinking.', 'Reset', 'Clear Space', 'Easy', 10, 'I have 10-15 minutes', 'I want to reset my life', array['short', 'doable', 'reset', 'admin', 'focus', 'money']::text[], 'Starter', 0, 'One small friction spot can create repeated mental drag.', 'One drawer, shelf, bag pocket, desk corner, or bedside surface is visibly reset.', 'What became easier after this tiny reset?', null, false, true),
  ('i_want_to_reset_my_life_i_have_10_15_minutes_2_triage_ten_messages', 'Triage Ten Messages', 'Open one inbox or message app and process exactly ten items: reply, archive, delete, save, or schedule.', 'Reset', 'Clear Space', 'Easy', 10, 'I have 10-15 minutes', 'I want to reset my life', array['short', 'doable', 'reset', 'admin', 'focus', 'money']::text[], 'Starter', 0, 'Small digital piles create avoidable background stress.', 'Ten messages or emails are processed.', 'Which message needed less energy than you expected?', null, false, true),
  ('i_want_to_reset_my_life_i_have_10_15_minutes_3_choose_three_today_priorities', 'Choose Three Today Priorities', 'Write three priorities for the next 24 hours: one must-do, one maintenance task, and one human or health action.', 'Reset', 'Clear Space', 'Easy', 10, 'I have 10-15 minutes', 'I want to reset my life', array['short', 'doable', 'reset', 'admin', 'focus', 'money']::text[], 'Starter', 0, 'A reset starts when the day has fewer competing demands.', 'Three priorities are written for the next 24 hours.', 'Which priority would make the biggest difference?', null, false, true),
  ('i_want_to_reset_my_life_i_have_15_30_minutes_1_audit_one_recurring_charge', 'Audit One Recurring Charge', 'Check your bank, wallet, app store, or email for one recurring charge and cancel, pause, downgrade, or set a dated decision reminder.', 'Reset', 'Clear Space', 'Medium', 25, 'I have 15-30 minutes', 'I want to reset my life', array['doable', 'focus', 'meaningful', 'reset', 'admin', 'money']::text[], 'Starter', 0, 'Recurring charges can quietly drain money and attention when they are never reviewed.', 'One recurring charge is handled or given a dated reminder.', 'How much attention or money did this charge deserve?', null, false, true),
  ('i_want_to_reset_my_life_i_have_15_30_minutes_2_clean_one_digital_folder', 'Clean One Digital Folder', 'Choose one folder, desktop area, notes app, or downloads folder and delete, rename, or move at least 20 items.', 'Reset', 'Clear Space', 'Medium', 25, 'I have 15-30 minutes', 'I want to reset my life', array['doable', 'focus', 'meaningful', 'reset', 'admin', 'money']::text[], 'Starter', 0, 'Digital clutter makes it harder to find your own work and decisions.', 'At least 20 digital items are deleted, renamed, or moved.', 'What did this folder say about what you have been avoiding?', null, false, true),
  ('i_want_to_reset_my_life_i_have_15_30_minutes_3_finish_one_25_minute_block', 'Finish One 25-Minute Block', 'Work for 25 minutes on one important task with distractions closed, then save, send, or write down the visible progress you made.', 'Reset', 'Clear Space', 'Medium', 25, 'I have 15-30 minutes', 'I want to reset my life', array['doable', 'focus', 'meaningful', 'reset', 'admin', 'money']::text[], 'Starter', 0, 'Execution confidence grows when a real block gets completed, not planned.', 'One 25-minute focus block is completed with visible progress captured.', 'What did the focused block move forward?', null, false, true),
  ('i_want_to_reset_my_life_i_have_more_than_30_minutes_1_reset_your_main_workspace', 'Reset Your Main Workspace', 'Spend 45 minutes resetting your main work or study space: clear surfaces, organize tools, remove clutter, and prepare the next task.', 'Reset', 'Clear Space', 'Hard', 50, 'I have more than 30 minutes', 'I want to reset my life', array['deep', 'purpose', 'reset', 'admin', 'focus', 'money']::text[], 'Starter', 0, 'A usable workspace lowers the starting cost of future action.', 'Your main workspace is cleaner and ready for the next task.', 'What will be easier to start now?', null, false, true),
  ('i_want_to_reset_my_life_i_have_more_than_30_minutes_2_do_a_life_admin_hour', 'Do a Life Admin Hour', 'Spend one hour on admin you have delayed: appointments, documents, payments, forms, files, repairs, or scheduling.', 'Reset', 'Clear Space', 'Hard', 50, 'I have more than 30 minutes', 'I want to reset my life', array['deep', 'purpose', 'reset', 'admin', 'focus', 'money']::text[], 'Starter', 0, 'Life admin stops feeling like a monster when it gets a contained hour.', 'One hour of delayed admin is completed with a written progress note.', 'Which admin task lost power once you touched it?', null, false, true),
  ('i_want_to_reset_my_life_i_have_more_than_30_minutes_3_run_a_weekly_reset', 'Run a Weekly Reset', 'Review the next seven days, choose three priorities, clear one space, and prepare one item for tomorrow.', 'Reset', 'Clear Space', 'Hard', 50, 'I have more than 30 minutes', 'I want to reset my life', array['deep', 'purpose', 'reset', 'admin', 'focus', 'money']::text[], 'Starter', 0, 'A weekly reset gives the next few days a calmer starting point.', 'Your week has three priorities, one cleared space, and one prepared item.', 'What does the next week need less of?', null, false, true),
  ('i_want_to_do_something_creative_i_only_have_5_minutes_1_make_a_messy_doodle', 'Make a Messy Doodle', 'Draw, sketch, map, or scribble one messy idea for five minutes without fixing it.', 'Build', 'Spark Lab', 'Easy', 10, 'I only have 5 minutes', 'I want to do something creative', array['quick', 'easy', 'creative', 'expression', 'craft']::text[], 'Starter', 0, 'Tiny making breaks the spell of only consuming.', 'One messy visual idea exists on paper or screen.', 'What appeared when you stopped trying to make it good?', null, false, true),
  ('i_want_to_do_something_creative_i_only_have_5_minutes_2_record_a_raw_idea_note', 'Record a Raw Idea Note', 'Record or write a one-minute raw idea note about something you might want to make, say, build, cook, or explore.', 'Build', 'Spark Lab', 'Easy', 10, 'I only have 5 minutes', 'I want to do something creative', array['quick', 'easy', 'creative', 'expression', 'craft']::text[], 'Starter', 0, 'A raw idea captured today can become material later.', 'One raw idea note is saved.', 'What part of the idea still has energy?', null, false, true),
  ('i_want_to_do_something_creative_i_only_have_5_minutes_3_title_five_possible_things', 'Title Five Possible Things', 'Write five possible titles for essays, videos, photos, projects, recipes, designs, songs, or posts.', 'Build', 'Spark Lab', 'Easy', 10, 'I only have 5 minutes', 'I want to do something creative', array['quick', 'easy', 'creative', 'expression', 'craft']::text[], 'Starter', 0, 'Titles give vague creative energy a handle.', 'Five possible titles are written.', 'Which title wants to become real first?', null, false, true),
  ('i_want_to_do_something_creative_i_have_10_15_minutes_1_make_one_tiny_thing', 'Make One Tiny Thing', 'Create one small thing without judging it: a doodle, note, voice memo, photo, melody, rough paragraph, or layout.', 'Build', 'Spark Lab', 'Easy', 10, 'I have 10-15 minutes', 'I want to do something creative', array['short', 'doable', 'creative', 'expression', 'craft']::text[], 'Starter', 0, 'Making something small turns passive time into evidence that you are still in motion.', 'You make one tiny thing and give it a title.', 'What did you make, and what would you call it?', null, false, true),
  ('i_want_to_do_something_creative_i_have_10_15_minutes_2_remix_one_old_idea', 'Remix One Old Idea', 'Find one old note, photo, draft, or idea and turn it into a slightly newer version.', 'Build', 'Spark Lab', 'Easy', 10, 'I have 10-15 minutes', 'I want to do something creative', array['short', 'doable', 'creative', 'expression', 'craft']::text[], 'Starter', 0, 'Old ideas often need motion, not a perfect fresh start.', 'One old idea has a new version, angle, or next step.', 'What was still useful in the old idea?', null, false, true),
  ('i_want_to_do_something_creative_i_have_10_15_minutes_3_create_a_tiny_moodboard', 'Create a Tiny Moodboard', 'Collect five images, words, colors, sounds, or references that match the feeling of something you want to make.', 'Build', 'Spark Lab', 'Easy', 10, 'I have 10-15 minutes', 'I want to do something creative', array['short', 'doable', 'creative', 'expression', 'craft']::text[], 'Starter', 0, 'Creative direction gets clearer when the feeling becomes visible.', 'A five-piece moodboard or reference list is created.', 'What feeling connects the pieces?', null, false, true),
  ('i_want_to_do_something_creative_i_have_15_30_minutes_1_make_the_rough_first_version', 'Make the Rough First Version', 'Create a rough first version of one idea: sketch, outline, voice note, mockup, recipe test, photo study, or tiny build.', 'Build', 'Spark Lab', 'Medium', 25, 'I have 15-30 minutes', 'I want to do something creative', array['doable', 'focus', 'meaningful', 'creative', 'expression', 'craft']::text[], 'Starter', 0, 'A rough version gives your idea a shape you can improve instead of just imagine.', 'You create and save one rough version of an idea.', 'What became clearer once the idea existed outside your head?', null, false, true),
  ('i_want_to_do_something_creative_i_have_15_30_minutes_2_finish_a_tiny_creative_artifact', 'Finish a Tiny Creative Artifact', 'Finish one small creative artifact enough to share, store, or revisit: a page, beat, sketch, edit, recipe, clip, or layout.', 'Build', 'Spark Lab', 'Medium', 25, 'I have 15-30 minutes', 'I want to do something creative', array['doable', 'focus', 'meaningful', 'creative', 'expression', 'craft']::text[], 'Starter', 0, 'Completion teaches your creative brain that ideas can land.', 'One tiny artifact is finished to a clear stopping point.', 'What did finishing teach you about the idea?', null, false, true),
  ('i_want_to_do_something_creative_i_have_15_30_minutes_3_practice_one_creative_technique', 'Practice One Creative Technique', 'Choose one technique and practice it for 20 minutes: line work, editing, lighting, rhythm, color, writing, camera, or layout.', 'Build', 'Spark Lab', 'Medium', 25, 'I have 15-30 minutes', 'I want to do something creative', array['doable', 'focus', 'meaningful', 'creative', 'expression', 'craft']::text[], 'Starter', 0, 'Skill grows when practice has one clear target.', 'One creative technique is practiced for 20 minutes.', 'What improved even slightly?', null, false, true),
  ('i_want_to_do_something_creative_i_have_more_than_30_minutes_1_do_a_deep_creative_block', 'Do a Deep Creative Block', 'Spend 60 minutes making one thing with notifications off and a clear finish line for the session.', 'Build', 'Spark Lab', 'Hard', 50, 'I have more than 30 minutes', 'I want to do something creative', array['deep', 'purpose', 'creative', 'expression', 'craft']::text[], 'Starter', 0, 'Longer creative work needs protected time more than inspiration.', 'One 60-minute creative block is completed with a saved output.', 'What did the protected block make possible?', null, false, true),
  ('i_want_to_do_something_creative_i_have_more_than_30_minutes_2_build_a_shareable_mini_piece', 'Build a Shareable Mini Piece', 'Create a small piece you could show someone: a short post, photo set, recipe, design, demo, poem, page, or recording.', 'Build', 'Spark Lab', 'Hard', 50, 'I have more than 30 minutes', 'I want to do something creative', array['deep', 'purpose', 'creative', 'expression', 'craft']::text[], 'Starter', 0, 'Shareable does not mean perfect. It means the idea has left your head.', 'One mini piece is created and ready to show or store.', 'What would you improve next, not before sharing?', null, false, true),
  ('i_want_to_do_something_creative_i_have_more_than_30_minutes_3_take_a_creative_field_trip', 'Take a Creative Field Trip', 'Go somewhere that can feed your creativity: market, street, library, gallery, park, bookstore, cafe, or hardware store, and collect five references.', 'Build', 'Spark Lab', 'Hard', 50, 'I have more than 30 minutes', 'I want to do something creative', array['deep', 'purpose', 'creative', 'expression', 'craft']::text[], 'Starter', 0, 'New input from the real world gives creativity better raw material.', 'You visit one place and collect five creative references.', 'What did the place give you that your room could not?', null, false, true)

on conflict (mission_id_slug) do update set
  title = excluded.title,
  mission = excluded.mission,
  world = excluded.world,
  category = excluded.category,
  difficulty = excluded.difficulty,
  xp = excluded.xp,
  time_required = excluded.time_required,
  mission_path = excluded.mission_path,
  tags = excluded.tags,
  pack = excluded.pack,
  unlock_xp = excluded.unlock_xp,
  why_it_matters = excluded.why_it_matters,
  completion_condition = excluded.completion_condition,
  reflection_prompt = excluded.reflection_prompt,
  safety_note = excluded.safety_note,
  is_sensitive = excluded.is_sensitive,
  is_active = excluded.is_active;
